    if not G or not V then return 0, false end
    local Z = V .. (":" .. G)
    local j = i.AssetCache[Z]
    if j then return j, true end
    local c = i.EggsNoIcons[G]
    if c then return c, true end
    local J, T = pcall(function() return y.FindItemImage(G, V) end)
    if not J or not T then
        i.AssetCache[Z] = 0
        return 0, false
    end
    local d = tonumber(string.match(T, "%d+")) or 0
    local u = false
    if d == 6937742258 then
        d = 0
        u = true
    end
    i.AssetCache[Z] = d
    return d, true, u
end
