    end
    local function j(G, V, Z)
        return string.format("#%02X%02X%02X", y(math.floor(G + .5), 0, 255),
            y(math.floor(V + .5), 0, 255), y(math.floor(Z + .5), 0, 255))
    end
    local function i(G, V, y)
        G = ((G % 360)) / 360
        local function Z(G, V, y)
            if y < 0 then y = y + 1 end
            if y > 1 then y = y - 1 end
            if y < .16666666666667 then return G + (((V - G)) * 6) * y end
            if y < .5 then return V end
            if y < .66666666666667 then return G + (((V - G)) * ((.66666666666667 - y))) * 6 end
            return G
        end
        if V == 0 then
            local G = y * 255
            return G, G, G
        end
        local j = y < .5 and y * ((1 + V)) or (y + V) - y * V
        local i = 2 * y - j
