        if J < T then J, T = T, J end
        return ((J + .05)) / ((T + .05))
    end
    local T = 0
    for V = 1, #G, 1 do T = (((T * 131) + string.byte(G, V))) % 2147483647 end
    local d, u, q = Z(V)
    local g = T % 360
    local E = .72
    local a = { .62, .68, .74, .8 }
    local H, r, Y = 255, 255, 255
    local e = 0
    for G, V in ipairs(a) do
        local y, Z, j = i(g, E, V)
        local c = J(y, Z, j, d, u, q)
        if c > e then
            H, r, Y = y, Z, j
            e = c
        end
    end
    while e < 4.5 do
        H = H + (((255 - H)) * .18)
        r = r + (((255 - r)) * .18)
        Y = Y + (((255 - Y)) * .18)
        e = J(H, r, Y, d, u, q)
    end
    local s = H * .18
    local N = r * .18
