h.CompilePassiveBio = function(G, V, y)
    if not V or not V.Description then return "No description available." end
    local function Z(G, V)
        local y = 10 ^ ((V or 2))
        return math.floor(G * y + .5) / y
    end
    local function j(G)
        if not G then return "0:00" end
        local V = math.abs(G)
        local y = math.floor(V / 60)
        local Z = math.floor(V % 60)
        local j = G < 0 and "-" or ""
        return string.format("%s%d:%02d", j, y, Z)
    end
    local function i(G, V)
        if not G then return "nil" end
        if V == "ColonTime" then
            return j(G)
        elseif V == "Percentage" then
            return Z(G * 100, 1) .. "%"
        elseif V == "NoPrecision" then
            return
                math.floor(G)
        else
            return Z(G, 2)
        end
    end
    local c = V.Description
    local J = V.States or {}
    local T = y or 1
    local d = c:gsub("<([%w_]+)>",
        function(G)
            local V = J[G]
            if not V then return "<" .. (G .. ">") end
            local y = ((V.Base or 0)) + (((V.Scale or 0)) * T)
            if V.Scale and (V.Scale > 0 and V.Max) then y = math.min(y, V.Max) end
            if V.Scale and (V.Scale < 0 and V.Min) then y = math.max(y, V.Min) end
            local Z = i(y, V.Formatter)
            if V.Formatter == "Percentage" then return string.sub(Z, 1, -2) end
            return Z
        end)
    local u = {}
    local q = {}
    for G in pairs(J) do table.insert(q, G) end
    table.sort(q)
    for G, V in ipairs(q) do
        local y = J[V]
        local Z = {}
        if y.Base then table.insert(Z, "Base: " .. i(y.Base, y.Formatter)) end
        if y.Scale and y.Scale ~= 0 then table.insert(Z, "Scale: " .. i(y.Scale, y.Formatter)) end
        if y.Min then table.insert(Z, "Min: " .. i(y.Min, y.Formatter)) end
        if y.Max then table.insert(Z, "Max: " .. i(y.Max, y.Formatter)) end
        if #Z > 0 then table.insert(u, string.format("<b>%s</b>: [%s]", V, table.concat(Z, " | "))) end
    end
    local g = string.format("<b><font size=\'16\'>%s</font></b>\n%s", G, d)
    if #u > 0 then
        local G = table.concat(u, "\n")
        g = g .. ("\n\n<font color=\'#AAAAAA\' size=\'14\'>-- Technical Stats --\n" .. (G .. "</font>"))
    end
    return g
end
