        local G = {}
        local V = H.mFarm
        local y = V and V:FindFirstChild("Important")
        local Z = y and y:FindFirstChild("Plant_Locations")
        if not Z then return G end
        for V, y in ipairs(Z:GetChildren()) do if y.Name == "Can_Plant" and y:IsA("BasePart") then table.insert(G, y) end end
        return G
    end,
    GetPointInsideCanPlantSeedPlacement = function(G)
        if not G or not G:IsA("BasePart") then return nil end
        local V = G.Size
        local y = 1
        local Z = ((math.random() - .5)) * math.max(.1, V.X - y)
        local j = ((math.random() - .5)) * math.max(.1, V.Z - y)
        local i = ((G.CFrame * CFrame.new(Z, (V.Y / 2) + 15, j))).Position
        local c = RaycastParams.new()
        c.FilterType = Enum.RaycastFilterType.Include
        c.FilterDescendantsInstances = { G }
        local J = workspace:Raycast(i, Vector3.new(0, -60, 0), c)
        if J and J.Position then return J.Position end
        return ((G.CFrame * CFrame.new(Z, V.Y / 2, j))).Position
    end,
    IsCanPlantSpotBlockedSeedPlacement = function(G, V)
        if not G then return true end
        V = tonumber(V) or 2
        if H.Plants_Physical then
            local V = H.Plants_Physical:GetChildren()
            if #V > 0 then
                local y = RaycastParams.new()
                y.FilterType = Enum.RaycastFilterType.Include
                y.FilterDescendantsInstances = V
                local Z = workspace:Raycast(G + Vector3.new(0, 25, 0), Vector3.new(0, -60, 0), y)
                if Z and Z.Instance then return true end
            end
        end
        local y = Vector3.new(G.X, 0, G.Z)
        for G, Z in ipairs(H.Get_Plants_Physical_Objects()) do
            local j, i = pcall(function() return Z:GetPivot() end)
            if j and i then
                local G = Vector3.new(i.Position.X, 0, i.Position.Z)
                if ((G - y)).Magnitude <= V then return true end
            end
        end
        return false
    end,
    GetRandomCanPlantPositionSeedPlacement = function(G, V)
        local y = H.SeedPlacement.GetCanPlantPartsSeedPlacement()
        if #y <= 0 then return nil, "No Can_Plant parts found" end
        G = tonumber(G) or 45
        V = tonumber(V) or 2
        for G = 1, G, 1 do
            local Z = y[math.random(1, #y)]
            local j = H.SeedPlacement.GetPointInsideCanPlantSeedPlacement(Z)
            if j and not H.SeedPlacement.IsCanPlantSpotBlockedSeedPlacement(j, V) then return j, "OK" end
        end
        return nil, "No free Can_Plant spot"
    end
}
H.GetRandomCanPlantSeedPosition = function(G, V) return H.SeedPlacement.GetRandomCanPlantPositionSeedPlacement(G, V) end
