    LoadProductsPremiumMarket = function(G)
        local V = A.PremiumMarket
        if V.is_loading then
            V.NotifyPremiumMarket("Market is already loading", 2)
            return false
        end
        if V.loaded and G ~= true then
            V.NotifyPremiumMarket("Market already loaded", 2)
            return true
        end
        if not V.CheckRequiredPremiumMarket(false) then return false end
        if type(y.MarketplaceService.GetDeveloperProductsAsync) ~= "function" then
            V.SetStatusPremiumMarket("\226\157\140 Developer products API is missing.")
            V.NotifyPremiumMarket("Developer products API is missing", 3)
            return false
        end
        V.is_loading = true
        V.loaded = false
        V.loaded_count = 0
        V.giftable_count = 0
        V.selected_product_id = 0
        V.products_by_id = {}
        V.product_order = {}
        V.BuildGiftMapsPremiumMarket()
        V.SetStatusPremiumMarket("Loading market products...")
        V.UpdateInfoPremiumMarket(0)
        V.RebuildDropdownPremiumMarket()
        local Z, j = V.SafeCallPremiumMarket("GetDeveloperProductsAsync",
            function() return y.MarketplaceService:GetDeveloperProductsAsync() end)
        if not Z or not j then
            V.is_loading = false
            V.SetStatusPremiumMarket("\226\157\140 Failed to load market products.")
            V.NotifyPremiumMarket("Failed to load market products", 3)
            return false
        end
        local i = j
        while true do
            local G, y = V.SafeCallPremiumMarket("GetCurrentPage", function() return i:GetCurrentPage() end)
            if G and type(y) == "table" then
                for G, y in ipairs(y) do
                    local Z = tonumber(y.ProductId)
                    local j = tostring(y.Name or "")
                    if Z and (Z > 0 and (j ~= "" and not V.products_by_id[Z])) then
