                        table.insert(V.product_order, Z)
                        V.loaded_count = V.loaded_count + 1
                        if V.GetGiftNamePremiumMarket(Z) then V.giftable_count = V.giftable_count + 1 end
                    end
                end
            end
            if i.IsFinished then break end
            local Z = V.SafeCallPremiumMarket("AdvanceToNextPageAsync", function() i:AdvanceToNextPageAsync() end)
            if not Z then break end
            task.wait()
        end
        table.sort(V.product_order,
            function(G, y)
                local Z = V.products_by_id[G]
                local j = V.products_by_id[y]
                local i = Z and (tostring(Z.Name or G)):lower() or tostring(G)
                local c = j and (tostring(j.Name or y)):lower() or tostring(y)
                return i < c
            end)
        V.loaded = true
        V.is_loading = false
        V.RebuildDropdownPremiumMarket()
        V.SetStatusPremiumMarket(string.format("\226\156\133 Loaded %d products. Giftable: %d.", V.loaded_count,
            V.giftable_count))
        V.NotifyPremiumMarket("Market loaded: " .. (tostring(V.loaded_count) .. " products"), 3)
        return true
    end,
