                    local i = j.seed
                    local c = d[i] - ((y[i] and y[i].placeamount or 0))
                    if c > 0 and G > 0 then
                        y[i] = y[i] or { placeamount = 0 }
                        y[i].placeamount = y[i].placeamount + 1
                        G = G - 1
                        V = true
                    end
                end
                if not V then break end
            end
        end
    end
    local u = 1
    while T > 0 do
        local V = false
        for Z = 1, c, 1 do
            local j = i[u]
            local J = G[j]
            if J and #J > 0 then
                for G, Z in ipairs(J) do
                    local j = Z.seed
                    local i = d[j] - ((y[j] and y[j].placeamount or 0))
