                break
            end
            for V, y in ipairs(d.data) do
                local Z = y.id
                local j = tonumber(y.playing) or 0
                local J = tonumber(y.maxPlayers) or 0
                if Z and (Z ~= game.JobId and (not A.Hop.TriedServers[Z] and (J > 0 and j < J))) then
                    if j <= G then
                        table
                            .insert(i, y)
                    else
                        table.insert(c, y)
                    end
                end
            end
            j = d.nextPageCursor
            if not j then break end
            task.wait(.15)
        end
        local J = #i > 0 and i or c
        if #J == 0 then
            warn("[Hop] No non-full server found")
            return nil
        end
        local T = J[math.random(1, #J)]
        print(string.format("[Hop] Selected: %s (%d/%d)", T.id, T.playing or 0, T.maxPlayers or 0))
        return T.id, T
    end,
    HopToNewServer = function()
        local G = game:GetService("Players")
        local V = game:GetService("TeleportService")
        local y = G.LocalPlayer
        for G = 1, 5, 1 do
            local Z, j = A.Hop.FindBestServer()
            if not Z or Z == "" then
                warn("[Hop] No valid JobId")
                return false
            end
            A.Hop.TriedServers[Z] = true
            local i, c = pcall(function() V:TeleportToPlaceInstance(game.PlaceId, Z, y) end)
            if i then return true end
            warn("[Hop] Teleport failed, trying another:", c)
            task.wait(.5)
        end
        warn("[Hop] All hop attempts failed")
        return false
    end,
    TeleportToJobId = function(G, V)
