            warn("[TeleportToJobId] Missing JobId")
            return false
        end
        if not V or V <= 0 then
            warn("[TeleportToJobId] Invalid PlaceId")
            return false
        end
        local c, J = pcall(function() j:TeleportToPlaceInstance(V, G, i) end)
        if not c then
            warn("[TeleportToJobId] Failed:", J)
            return false
        end
        return true
    end
}
