h.getColorFromName = function(G)
    if type(G) ~= "string" or #G == 0 then return "#969696" end
    local V = 0
    for y = 1, #G, 1 do
        local Z = string.byte(G, y)
        if Z then V = ((V * 31 + Z)) % 16777215 end
    end
    local y = bit32.rshift(V, 16) % 256
    local Z = bit32.rshift(V, 8) % 256
    local j = V % 256
    local i = G:lower()
    local c = i:find("common") ~= nil or i:find("uncommon") ~= nil
    if c then
        local G = math.clamp(math.floor((((y + Z) + j)) / 3), 120, 180)
        return string.format("#%02X%02X%02X", G, G, G)
    else
        y = math.clamp(y + 60, 0, 255)
        Z = math.clamp(Z + 60, 0, 255)
        j = math.clamp(j + 60, 0, 255)
        return string.format("#%02X%02X%02X", y, Z, j)
    end
end
