    local V = 0
    for G, y in pairs(T.bearded_dragon_egg_status or {}) do V = V + y end
    table.insert(G, string.format("Total Collected: <b><font color=\'#EF2E92\'>%d</font></b>", V))
    for V, y in pairs(T.bearded_dragon_egg_status or {}) do
        local Z = h.getColorFromName(V)
        table.insert(G, string.format("<font color=\'%s\'>%s</font>: <b>%d</b>", Z, V, y))
    end
    c.lbl_dragon_item_collected:SetText(table.concat(G, "\n"))
end
