r.Vector3ToCFrame = function(G)
    if not G then return nil end
    return CFrame.new(G)
end
r.StringToVector3 = function(G)
    if not G then return nil end
    local V, y, Z = G:match("([^,]+),([^,]+),([^,]+)")
    if not V or not y or not Z then return nil end
    return Vector3.new(tonumber(V), tonumber(y), tonumber(Z))
end
r.GetCurrentCFrameFromPlayer = function()
    local G = y.Character and y.Character:FindFirstChild("HumanoidRootPart")
    return G and G.CFrame or nil
end
r.GetCurrentCFrameFromPlayerString = function()
    local G = y.Character and y.Character:FindFirstChild("HumanoidRootPart")
    if not G then return nil end
    local V = G.Position
    return string.format("%f,%f,%f", V.X, V.Y, V.Z)
end
r.IsWithinRangeOfFarm = function(G, V)
    local y = 70.8
    local Z = Vector3.new(G.X, 0, G.Z)
    local j = Vector3.new(V.X, 0, V.Z)
    local i = ((G - V)).Magnitude
    return i > y
end
r.GetPlantIfPlantWithinPosition3D = function(G, V)
    local y = ((G - V)).Magnitude
    return y < 1
end
r.GetPlantIfPlantWithinPositionXZ = function(G, V)
    local y = Vector3.new(G.X, 0, G.Z)
    local Z = Vector3.new(V.X, 0, V.Z)
    local j = ((y - Z)).Magnitude
    return j < 1.3
end
r.GetAllPlantsOnFarmForTrowel = function(G)
    local V = {}
    local y = T.trowel_plants_list
    local Z = y and next(y) ~= nil
    for j, i in ipairs(H.Get_Plants_Physical_Objects()) do
        if Z and not y[i.Name] then continue end
        if G then
            local V = (i:GetPivot()).Position
            if r.GetPlantIfPlantWithinPositionXZ(V, G) then continue end
        end
        V[#V + 1] = i
    end
    return V
end
r.FindTrowelTool = function()
    for G, V in ipairs(y.Backpack:GetChildren()) do
        if not V:IsA("Tool") then continue end
        local y = V:GetAttribute("b")
        if not y then continue end
        if string.find(V.Name, "Trowel", 1, true) then return V end
    end
    for G, V in ipairs(y.Character:GetChildren()) do
        if not V:IsA("Tool") then continue end
        local y = V:GetAttribute("b")
        if not y then continue end
        if string.find(V.Name, "Trowel", 1, true) then return V end
    end
    return nil
end
r.PickUpPlantUsingTrowel = function(G, V)
