end
r.PlacePlantUsingTrowel = function(G, V, Z)
    local j, i = pcall(function()
        y.TrowelRemote:InvokeServer("Place", G, V, r.Vector3ToCFrame(Z))
        task.wait(.3)
    end)
    if i then warn("PlacePlantUsingTrowel: ", i) end
    return j
end
r.TrowelLoop = function()
    if f.Is_MasterBusy() then
        r.UpdateTrowelStatus("\240\159\165\154 Paused: tasks in progress.")
        return false
    end
    if not r.trowel_is_running then
        r.UpdateTrowelStatus("\240\159\148\180 Not Running...")
        return false
    end
    local G = r.StringToVector3(T.trowel_saved_cframe)
    if not G then
        r.UpdateTrowelStatus("\240\159\148\180 Stopping: Location invalid...")
        r.trowel_is_running = false
        return false
    end
    local V = r.GetAllPlantsOnFarmForTrowel(G)
    if not V or #V == 0 then
        r.UpdateTrowelStatus("\240\159\148\180 Stopping: No plants to move...")
        r.trowel_is_running = false
        return false
    end
    local y = r.FindTrowelTool()
    if not y then
        r.UpdateTrowelStatus("\240\159\148\180 Stopping: No trowel found...")
        r.trowel_is_running = false
        return false
    end
    i.trowel_count_total_to_move = #V
    i.trowel_current_moved = 0
    local Z = 0
    r.UpdateTrowelStatus("\240\159\159\162 Active and running...")
    r.UpdateTrowelProgress(string.format("\240\159\148\132 <font color=\'#32CD32\'>Moving </font> %d/%d",
        i.trowel_current_moved, i.trowel_count_total_to_move))
    jJ()
    task.wait(.3)
    if not ZJ(y) then return false end
    for V, j in ipairs(V) do
        if not r.trowel_is_running then
            r.UpdateTrowelStatus("\226\157\140 Stopped by user.")
            break
        end
        if f.Is_MasterBusy() then
            r.UpdateTrowelStatus("\226\143\184\239\184\143 Paused mid-process...")
            break
        end
        if not MJ(y) then
            r.UpdateTrowelStatus("\226\157\140 Tool not held. Equipping... ")
            jJ()
            task.wait(.3)
            ZJ(y)
            Z = Z + 1
            task.wait(1)
            if Z > 15 then
                r.UpdateTrowelStatus("\240\159\148\180 Failed to hold tool after 15 tries.")
                break
            end
        end
        local c = r.PickUpPlantUsingTrowel(y, j)
        if not c then
            r.UpdateTrowelStatus("\226\157\140 Failed to pick up: " .. tostring(j.Name))
            continue
        end
        task.wait(.1)
        local J = r.PlacePlantUsingTrowel(y, j, G)
        if not J then
            r.UpdateTrowelStatus("\226\157\140 Failed to place: " .. tostring(j.Name))
            continue
        end
        i.trowel_current_moved = i.trowel_current_moved + 1
        r.UpdateTrowelStatus("\240\159\159\162 Success " .. tostring(j.Name))
        r.UpdateTrowelProgress(string.format("\240\159\148\132 <font color=\'#32CD32\'>Moving </font> %d/%d",
            i.trowel_current_moved, i.trowel_count_total_to_move))
        task.wait(.1)
    end
    jJ()
    if i.trowel_current_moved >= i.trowel_count_total_to_move then
        r.trowel_is_running = false
        r.UpdateTrowelStatus(
            "\226\156\133 All plants moved. If nothing moved please make sure to set cframe again and inside your farm.")
    end
    r.UpdateTrowelProgress(string.format("\240\159\147\138 Last Moved %d/%d", i.trowel_current_moved,
        i.trowel_count_total_to_move))
    return true
end
