h.CreateEventTeleportButton = function(G)
    local V = y.PlayerGui:FindFirstChild("Teleport_UI")
    if not V then return end
    local Z = V:FindFirstChild("Frame")
    if not Z then return end
    local j = Z:FindFirstChild("Garden")
    if not j or not j:IsA("ImageButton") then
        warn("Garden button missing")
        return
    end
    local i = j:Clone()
    i.Name = "Event"
    local c = i:FindFirstChildWhichIsA("TextLabel", true)
    if c then c.Text = "Event" end
    i.ImageColor3 = Color3.fromRGB(255, 140, 50)
    if G then
        if G.RemoveBG then
            i.Image = ""
            i.ImageTransparency = 1
        end
        if G.NewImage then
            i.Image = G.NewImage
            i.ImageTransparency = 0
        end
        if G.BGTransparency then i.ImageTransparency = G.BGTransparency end
    end
    i.Parent = Z
    if G and G.OnClick then i.MouseButton1Click:Connect(function() G.OnClick(i) end) end
    return i
end
h.ResizeTeleportButtons = function(G)
    local V = y.PlayerGui:FindFirstChild("Teleport_UI")
    if not V then return end
    local Z = V:FindFirstChild("Frame")
    if not Z then return end
    local j = .8
    for V, y in ipairs(Z:GetDescendants()) do
        if y:IsA("ImageButton") then
            if not h._originalTeleportSizes[y] then h._originalTeleportSizes[y] = y.Size end
            local V = h._originalTeleportSizes[y]
            if G then y.Size = UDim2.new(V.X.Scale * j, V.X.Offset * j, V.Y.Scale * j, V.Y.Offset * j) else y.Size = V end
        end
    end
end
