X.CraftStats = {
    SELECT_RECIPE = "SELECT_RECIPE",
    START_CRAFTING = "START_CRAFTING",
    SKIP_CRAFT = "SKIP_CRAFT",
    CLAIM_REWARDS =
    "CLAIM_REWARDS",
    SUBMIT_ITEM = "SUBMIT_ITEM"
