X.GetWorkbenchStateUsingName = function(G)
    local V = X.GetWorkBenchModelUsingName(G)
    if not V then return nil end
    local y = X.GetProximityPromptUsingModel(V)
    if not y then return nil end
    local Z = X.CraftStats.SELECT_RECIPE
    if y and (y:IsA("ProximityPrompt") and y.ActionText) then
        local G = y.ActionText
        if string.find(G, "Start Crafting", 1, true) then
            Z = X.CraftStats.START_CRAFTING
        elseif string.find(G, "Select Recipe", 1, true) then
            Z =
                X.CraftStats.SELECT_RECIPE
        elseif string.find(G, "Claim", 1, true) then
            Z = X.CraftStats.CLAIM_REWARDS
        elseif string.find(G, "Submit Item", 1, true) then
            Z =
                X.CraftStats.SUBMIT_ITEM
        elseif string.find(G, "Skip", 1, true) then
            Z = X.CraftStats.SKIP_CRAFT
        end
    else
    end
    return Z
end
