X.SetRecipeUsingName = function(G, V)
    local y = u.allcraft.receipe_data[G]
    if not y then return false end
    for y, Z in pairs(y) do
        local j = X.AllReceipeData[G]
        if not j then continue end
        local c = j[y].inputs
        local J = {}
        for G, V in ipairs(c) do
            local Z = V.Name
            local j = V.Type
            local c = nil
            if j == "PetBoost" then
                c = e.GetPetBoostUsingName(Z)
            elseif j == "Pet" then
                c = e.GetPetUsingNameForCraft(Z)
            elseif j == "CosmeticCrate" then
                c =
                    e.GetCosmeticCrateUsingName(Z)
            elseif j == "SprayBottle" then
                c = e.GetSprayBottleUsingName(Z)
            elseif j == "Sprinkler" then
                c =
                    e.GetSprinklerUsingName(Z)
            elseif j == "Harvest Tool" then
                c = e.GetHarvestTool()
            elseif j == "Recall Wrench" then
                c =
                    e.GetRecallWrench()
            elseif j == "Lightning Rod" then
                c = e.GetLightningRod()
            elseif j == "PetEgg" then
                c =
                    e.GetEggUsingName(Z)
            elseif j == "Holdable" then
                c = e.GetHoldableUsingName(Z)
            elseif j == "Seed" then
                c =
                    e.GetSeedUsingName(Z)
            elseif j == "Food" then
                c = e.GetFoodUsingName(Z)
            elseif j == "Smith Hammer of Harvest" then
                c =
                    e.GetSmithHammerofHarvest()
            else
                c = e.GetToolUsingNameNormalised(Z)
            end
            if not c then
                J = {}
                X.Current_Recipe_MissingItemName = X.Current_Recipe_MissingItemName .. (" " .. (Z .. ","))
                X.Current_Recipe_Name = X.Current_Recipe_Name .. (" " .. (y .. ","))
                if j == "Holdable" then
                    if g.HasPlantByName(Z) then
                        if T.craft_autofruit_workbench then
                            X.Update_GearEventWorkbenchStatus("\240\159\141\146 Trying to Collect fruits")
                            local G, V = pcall(function()
                                local G = {}
                                G[Z] = true
                                g.CollectFruitByNamesSortedRarity(G, 3)
                            end)
                            if not G then warn("Failed to collect fruit: " .. (Z .. " - "), V) end
                            task.wait(.5)
                        end
                    else
                        if T.craft_autoplant_workbench then
                            if not H.Garden.GetIsNormalGarden() then return false end
                            X.Update_GearEventWorkbenchStatus("\240\159\141\146 Trying to plant seed ", Z)
                            local G, V = pcall(function()
                                if not i.is_garden_full_seed then
                                    task.spawn(function()
                                        g
                                            .PlaceSeedSmart(Z, 2)
                                    end)
                                end
                            end)
                            if not G then warn("Failed to plant: " .. (Z .. " - "), V) end
                            task.wait(.5)
                        end
                    end
                end
                break
            end
            local d = c:GetAttribute("c")
            if j == "Pet" then
                local G = c:GetAttribute("PET_UUID")
                d = G
            end
            local u = { ItemName = Z, ItemType = j, ItemData = { UUID = d } }
            table.insert(J, u)
        end
        if #J > 0 then
            X.CreateRecipeWorkbenchUsingName(G, y)
            if not V then task.wait(1.5) end
            for y, Z in ipairs(J) do
                local j = Z.ItemType
                local c = Z.ItemName
                local J = { ItemType = Z.ItemType, ItemData = Z.ItemData }
                if j == "Pet" then
                    i.IS_CRAFTING = true
                    if not V then task.wait(1.5) end
                    local Z = e.GetPetUsingNameForCraft(c)
                    if Z then
                        jJ()
                        task.wait(.1)
                        ZJ(Z)
                        task.wait(.5)
                        X.SubmitRecipeWorkbenchUsingName(G, y, J)
                    end
                    i.IS_CRAFTING = false
                else
                    X.SubmitRecipeWorkbenchUsingName(G, y, J)
                end
                if not V then task.wait(.5) end
            end
            X.Current_Recipe_Name = y
            return true
        end
    end
    return false
end
f.FavouriteFruit = {
    is_unfav_running = false,
    IsFavouriteTarget = function(G)
        if not T.autofavfruits_enabled then return false end
        if typeof(G) ~= "Instance" then return false end
        if g.IsFavoriteFruitOnFarm(G) then return false end
        local V = type(T.autofavplantlist) == "table" and T.autofavplantlist or {}
        local y = tonumber(T.autofavminweight) or 70
        local Z = tonumber(T.autofavmaxweight) or 500
        local j = next(V) ~= nil
        local i = false
        if j then i = V[G.Name] == true else i = true end
        if not i then return false end
        local c = g.GetFruitWeight(G)
        if y and c < y then return false end
        if Z and c > Z then return false end
