    end,
    FavFruitsLoop = function()
        if not T.autofavfruits_enabled then return false end
        local G = type(T.autofavplantlist) == "table" and T.autofavplantlist or {}
        local V = tonumber(T.autofavminweight) or 70
        local y = tonumber(T.autofavmaxweight) or 500
        local Z, j = g.GetAllFruitsInFarmReady(G, V, y)
        if #Z > 0 then
            local G = e.GetFavouriteTool()
            if not G then return false end
            jJ()
            if ZJ(G) then
                pcall(function()
                    for V, y in ipairs(Z) do
                        f.FavouriteFruit.FavouriteFruit(G, y, true)
                        local Z = g.GetFruitWeight(y)
                        local j = string.format("%s %.2fKG", y.Name, Z)
                        i.Notify("\226\157\164\239\184\143 Favourite Fruit " .. j, 3)
                        task.wait(.5)
                        if not T.autofavfruits_enabled then break end
