}
X.CraftLoop = function()
    if f.Is_MasterBusy() then return false end
    if not u.allcraft.auto_craft_event then
        X.Update_GearEventWorkbenchStatus("\240\159\148\180 Not running")
        X.Update_GearEventWorkbenchTimers("\226\132\185\239\184\143 Select recipes and [Enable] to craft.")
        return false
    end
    for G, V in pairs(X.AllReceipeData) do
        if f.Is_MasterBusy() then break end
        local y = u.allcraft.receipe_data[G]
        if not y or next(y) == nil then continue end
        local Z = X.GetWorkbenchStateUsingName(G)
        if Z == nil then continue end
        if Z == X.CraftStats.SKIP_CRAFT then
            X.CraftTeams.PlaceTeamIdle()
            X.Update_GearEventWorkbenchStatus("\240\159\148\168 " .. (G .. " is Crafting"))
            continue
        elseif Z == X.CraftStats.SELECT_RECIPE then
            X.Update_GearEventWorkbenchStatus("\240\159\155\160\239\184\143 " .. (G .. " Attempting Recipe..."))
            local V, y = pcall(function() return X.SetRecipeUsingName(G) end)
            if V then
                if y == false then
                    local G = X.Current_Recipe_MissingItemName
                    X.Update_GearEventWorkbenchStatus(string.format(
                        "\226\157\140 Recipes <font color=\'#F527E7\'>%s</font> missing <font color=\'#F08080\'>%s</font>",
                        tostring(X.Current_Recipe_Name), tostring(G)))
                    X.Current_Recipe_Name = ""
                    X.Current_Recipe_MissingItemName = ""
                    i.IS_CRAFTING = false
                    continue
                end
            else
                X.Update_GearEventWorkbenchStatus("\226\157\140 " .. (G .. " Stop craft. Error occurred."))
            end
        elseif Z == X.CraftStats.START_CRAFTING then
            X.CraftTeams.PlaceTeamSubmitItems()
            X.StartCraftWorkbenchUsingName(G)
            X.Update_GearEventWorkbenchStatus("\226\156\133 " .. (G .. " Craft Started"))
        elseif Z == X.CraftStats.SUBMIT_ITEM then
            X.CancelWorkbenchUsingName(G)
        elseif Z == X.CraftStats.CLAIM_REWARDS then
            X.CraftTeams.PlaceTeamClaimItems()
            X.Update_GearEventWorkbenchStatus("\240\159\142\129 Claiming Rewards")
            X.ClaimWorkbenchUsingName(G)
            X.Current_Recipe_Name = ""
            task.wait(.2)
