    ProcessSummerRitualEvent = function()
        S.SummerRitualEvent.NormaliseSummerRitualSettings()
        if not u.summer_ritual.enabled then
            S.SummerRitualEvent.SetSummerRitualStatus("")
            return false
        end
        local G, V = pcall(function()
            if not S.SummerRitualEvent.ResolveSummerRitualRemotes() then
                S.SummerRitualEvent.SetSummerRitualStatus("Waiting for Summer Ritual remotes")
                return false
            end
            local G = S.SummerRitualEvent.GetSummerRitualEventData()
            if type(G) ~= "table" then
                S.SummerRitualEvent.SetSummerRitualStatus("Waiting for SummerFireEventData")
                return false
            end
            local V = S.SummerRitualEvent.GetSummerRitualStatus(G)
            local y = S.SummerRitualEvent.GetSummerRitualRequiredShards()
            local Z = S.SummerRitualEvent.GetSummerRitualFilledShards(G)
            local j = tonumber(G.InfernoShardProgress) or 0
            local i = S.SummerRitualEvent.CountSummerRitualShardTools()
            local c = S.SummerRitualEvent.GetSummerRitualCampfireTier()
            if V == "Complete" then
                S.SummerRitualEvent.SetSummerRitualStatus("Complete | Claim ready")
                if u.summer_ritual.auto_claim then
                    local G, V = S.SummerRitualEvent.ClaimSummerRitual()
                    S.SummerRitualEvent.SetSummerRitualStatus("Complete | " .. tostring(V or "Claiming"))
                    return G
                end
                return false
            end
            if V == "Active" then
                local V = S.SummerRitualEvent.GetSummerRitualRemainingTime(G)
                local y = S.SummerRitualEvent.GetSummerRitualTierSpeed(c)
                S.SummerRitualEvent.SetSummerRitualStatus(string.format("Active | %s left | Tier %s | x%s",
                    S.SummerRitualEvent.FormatSummerRitualTime(V or 0), c, y))
                return false
            end
            if Z < y then
                local G, c = S.SummerRitualEvent.PlaceSummerRitualShard()
                S.SummerRitualEvent.SetSummerRitualStatus(string.format(
                    "%s | Shards %s/%s | Bag %s | Progress %s/25 | %s", V,
                    Z, y, i, j, tostring(c or "Waiting")))
                return G
            end
            if tostring(G.RitualPet or "") == "" then
                local V, j, i, c = S.SummerRitualEvent.GetNextSummerRitualPetTool(G)
                if c then
                    S.SummerRitualEvent.SetSummerRitualStatus(i)
                    return false
                end
                if not V or not j then
                    S.SummerRitualEvent.SetSummerRitualStatus(string.format("Shards %s/%s ready | %s", Z, y,
                        tostring(i or "Waiting for pet")))
                    return false
                end
                local J, T = S.SummerRitualEvent.PlaceSummerRitualPet()
                S.SummerRitualEvent.SetSummerRitualStatus(string.format("Shards ready | Pet: %s | %s",
                    S.SummerRitualEvent.GetSummerRitualPetName(j), tostring(T or "Waiting")))
                return J
            end
            local J, T = S.SummerRitualEvent.CanStartSummerRitual(G)
            if u.summer_ritual.auto_start and J then
                local G, V = S.SummerRitualEvent.StartSummerRitual()
                S.SummerRitualEvent.SetSummerRitualStatus("Start | " .. tostring(V or "Starting"))
                return G
            end
            S.SummerRitualEvent.SetSummerRitualStatus(string.format("Ready | Shards %s/%s | Tier %s | %s", Z, y, c,
                tostring(T or "Waiting")))
            return false
        end)
        if not G then
            S.SummerRitualEvent.SetSummerRitualStatus("Error - check console")
            warn("[SummerRitualEvent]", V)
            return false
        end
        return V == true
    end
}
