                    Price = tonumber(Z.Price) or 0,
                    Rarity = tostring(Z.Rarity or "Unknown"),
                    HatchTime = tonumber(
                        Z.HatchTime) or 0,
                    Icon = Z.Icon,
                    StockChance = tonumber(Z.StockChance) or 0,
