h.SortPositionsByShape = function(G, V, y)
    if y == "random" then
        for V = #G, 2, -1 do
            local y = math.random(V)
            G[V], G[y] = G[y], G[V]
        end
        return
    end
    table.sort(G,
        function(G, Z)
            local j = G.X - V.X
            local i = G.Z - V.Z
            local c = Z.X - V.X
            local J = Z.Z - V.Z
            if y == "circle" then
                local G = j ^ 2 + i ^ 2
                local V = c ^ 2 + J ^ 2
                return G < V
            elseif y == "square" then
                local G = math.max(math.abs(j), math.abs(i))
                local V = math.max(math.abs(c), math.abs(J))
                return G < V
            elseif y == "heart" then
                local G = .15
                local function V(V, y)
                    local Z = V * G
                    local j = -((y * G)) + .5
                    local i = (((Z ^ 2 + j ^ 2) - 1)) ^ 3 - (Z ^ 2 * (j ^ 3))
                    return i
                end
                local y = V(j, i)
                local Z = V(c, J)
                return y < Z
            end
            return (j ^ 2 + i ^ 2) < (c ^ 2 + J ^ 2)
        end)
end
