    Z.QualityLevel = 1
    Z.MeshPartDetailLevel = Enum.MeshPartDetailLevel.Level01
    V.GlobalShadows = false
    V.FogEnd = 9000000000.0
    V.Brightness = 0
    V.Ambient = Color3.fromRGB(255, 255, 255)
    V.OutdoorAmbient = Color3.fromRGB(255, 255, 255)
    V.EnvironmentDiffuseScale = 0
    V.EnvironmentSpecularScale = 0
    V.ClockTime = 14
    for G, V in pairs(V:GetChildren()) do
        if V:IsA("PostEffect") or V:IsA("Sky") or V:IsA("Atmosphere") or V:IsA("Clouds") then
            V:Destroy()
        end
    end
    if G then
        G.WaterWaveSize = 0
        G.WaterReflectance = 0
        G.WaterTransparency = 0
        G.Decoration = false
        G.Material = Enum.Material.SmoothPlastic
    end
    for G, V in pairs(y.Workspace:GetDescendants()) do
        if V:IsA("Decal") or V:IsA("Texture") or V:IsA("SurfaceAppearance") then
            V:Destroy()
        elseif V:IsA("MeshPart") then
            V.TextureID = ""
            V.Material = Enum.Material.SmoothPlastic
            V.RenderFidelity = Enum.RenderFidelity.Performance
            V.Reflectance = 0
            V.CastShadow = false
        elseif V:IsA("SpecialMesh") then
            V.TextureId = ""
        elseif V:IsA("BasePart") then
            V.Material = Enum.Material.SmoothPlastic
            V.Reflectance = 0
            V.CastShadow = false
        elseif V:IsA("ParticleEmitter") or V:IsA("Trail") or V:IsA("Beam") or V:IsA("Fire") or V:IsA("Smoke") then
            V
                :Destroy()
        end
    end
end
