                    a:SetValue(T.g_fruit_weight_min)
                    return
                end
                if V < 0 then
                    i.Notify("Enter value 0 or more", 3)
                    a:SetValue(T.g_fruit_weight_min)
                    return
                end
                if V > tonumber(T.g_fruit_weight_max) then
