H.AutoStartEvents = function()
    if u.is_running_custom_teams then
        i.Notify("Starting teams system in 10s", 9)
        task.wait(10)
        t.StartCustomTeams()
    end
    if u.mut_system.is_ruuning then
        i.Notify("Auto resume pet mutation in 10s", 9)
        task.wait(10)
        t.StartThread()
        return
    end
    if T.mut_was_running then
        if u.is_running then
            T.mut_was_running = false
            GJ()
        end
        i.Notify("Auto resume mutation machine in 10s", 9)
        task.wait(10)
        s.StartThread()
        return
    end
    if u.is_running then
        task.spawn(function()
            i.Notify("Auto resume hatching in 10s", 7)
            local G = 10
            while G > 0 do
                task.wait(1)
                if not u.is_running then break end
                if not H.IsDataFullyLoaded() or not H.IsFarmFullyLoaded() then continue end
                G = G - 1
                if G <= 1 then
                    i.StartHatchingSystem()
                    break
                end
            end
        end)
    end
end
