q.chipmun_cd_current = 0
q.event_delayed_start = 15
q.havesubmittedforhatch = false
if not _G.FallEventLoop then
    _G.FallEventLoop = task.spawn(function()
        while true do
            task.wait(q.event_delayed_start)
            if i.IsPaused() then
                task.wait(math.random(2, 5))
                continue
            end
            q.event_delayed_start = 2
            i.QUEST_TASK_RUNNING = false
            if not H.IsDataFullyLoaded() or not H.IsFarmFullyLoaded() then
                task.wait(15)
                continue
            end
            if true then break end
            if not T.is_fall_event_running then
                q.UpdateStatsText("\240\159\148\180 Event is not enabled.")
                continue
            end
            if i.IS_HATCHING == true then
                q.UpdateStatsText("\240\159\165\154 Paused: Hatching in Progress.")
                if not q.havesubmittedforhatch then
                    q.SubmitFruits()
                    q.havesubmittedforhatch = true
                end
                task.wait(3)
                continue
            end
            q.havesubmittedforhatch = false
            local G = T.is_fall_event_fastmode
            q.UpdateStatsText("\240\159\159\162 Active and running...")
            local V = q.GetLookingForTrait()
            local y = q.GetCooldown()
            local Z = q.GetFallBlooms()
            if Z then q.UpdateStatsFallBloomText("\240\159\140\184 Fall Blooms: <b>" .. (Z .. "</b>")) end
            local j = q.GetProgressPercent()
            if j then q.UpdateStatsProgressText("\240\159\148\132 Progress: " .. (j .. "")) end
            if V then q.UpdateStatsRequiredText("\226\156\168 Looking for: <font color=\'#FF7800\'>" .. (V .. "</font> ")) end
            local c = { Vamp = true, Ghostly = true, Blight = true, Necrotic = true }
            local J = { Frozen = true, Chilled = true, Snowy = true, Ornamented = true, Glacial = true, Pepermint = true, Arctic = true }
            local d = {}
            for G, V in pairs(F) do d[G] = true end
            local u = { amount = 20, batch_mode = true, whitelist_mutation = J }
            if y then
                q.UpdateStatsProgressText("\226\143\179 Cooldown: <b>" .. (y .. " </b>"))
                task.wait(2)
                continue
            end
            q.SubmitFruits()
            q.ClaimRewardsTrack()
            if q.GetCooldown() then
                task.wait(3)
                continue
            end
            if V and V ~= "Any" then
                local y = d
                if y then
                    local Z = "<font color=\'#F5BB27\'>--- " .. (V .. "</font> Fruits ---\n")
                    for G, V in pairs(y) do
                        local y = string.format("%s\n", G)
                        Z = Z .. y
                    end
                    if e.IsBackpackFull() then
                        q.SubmitFruits()
                        continue
                    end
                    local j = false
                    if G then
                        while true do
                            task.wait(.5)
                            if not T.is_fall_event_running then break end
                            local V = false
                            if not G then break end
                            if i.IsPaused() then break end
                            if q.GetCooldown() then break end
                            q.UpdateStatsText("\240\159\159\162 Fast collect...")
                            local y = g.CollectFruitByNamesSortedRarityConfig(d, u)
                            task.wait(.2)
                            if not y then break end
                            q.SubmitFruits()
                            if i.IS_HATCHING or e.IsBackpackFull() then break end
                        end
                        task.wait(.1)
                    else
                        while true do
                            task.wait(.5)
                            if not T.is_fall_event_running then break end
                            if i.IS_HATCHING or e.IsBackpackFull() then break end
                            if G then break end
                            if q.GetCooldown() then break end
                            if i.IsPaused() then break end
                            q.UpdateStatsText("\240\159\159\162 Normal collect...")
                            u.amount = 9
                            u.batch_mode = false
                            local V = g.CollectFruitByNamesSortedRarityConfig(d, u)
                            if not V then
                                j = false
                                break
                            end
                            q.SubmitFruits()
                            j = true
