h.HighLightBackPack = function()
    local G = h.BackPackUiElements()
    local V = e.GetAllFruitsInBackpack()
    local y = e.GetAllPetsIn_Backpack()
    local Z = {}
    local j = {}
    for G, V in ipairs(V) do Z[V.Name] = V end
    for G, V in ipairs(y) do j[V.Name] = V end
    local i = os.clock()
    for G, V in ipairs(G) do
        if os.clock() - i > .005 then
            task.wait()
            i = os.clock()
        end
        local y = V:FindFirstChild("ToolName")
        if not y then continue end
        local c = y.Text
        local J = Z[c]
        local T = j[c]
        local d = nil
        local u = nil
        if T then
            local G = h.BackpackPetDetails(T)
            if G then
                d = string.format("%.2fKG", G)
                u = string.format(
                    "<stroke color=\"#14532D\" thickness=\"2\" sizing=\"fixed\" joins=\"round\"><font color=\"#FFFFFF\">weight: %s</font></stroke>",
                    d)
            end
        else
            if J then
                local G, V = h.BackpackFruitDetails(J)
                if V then
                    d = string.format("%s [%s KG]", G, V)
                    u = string.format("<stroke color=\"#FF0084\" thickness=\"1\">%s</stroke>", d)
                end
            end
        end
        local q = V:FindFirstChild("Label_kg")
        if not d then
            if q then q:Destroy() end
            continue
        end
        if not q then h.CreateTextOnElement("Label_kg", d, V) else if q.Text ~= u then q.Text = u end end
    end
end
