        T.Size = UDim2.fromScale(1, 0)
        T.AutomaticSize = Enum.AutomaticSize.Y
        T.BackgroundTransparency = 1
        T.Parent = J
        q = Instance.new("UIListLayout")
        q.FillDirection = Enum.FillDirection.Vertical
        q.HorizontalAlignment = Enum.HorizontalAlignment.Center
        q.VerticalAlignment = Enum.VerticalAlignment.Top
        q.Padding = UDim.new(0, 2)
        q.Parent = T
        d = Instance.new("TextLabel")
        d.Name = "MainLabel"
        d.Size = UDim2.fromScale(1, 0)
        d.AutomaticSize = Enum.AutomaticSize.Y
        d.BackgroundTransparency = 1
        d.TextScaled = false
        d.TextSize = 13
        d.RichText = true
        d.TextWrapped = true
        d.Font = Enum.Font.GothamBold
        d.TextStrokeTransparency = .4
        d.TextStrokeColor3 = Color3.new(0, 0, 0)
        d.TextColor3 = Color3.fromRGB(255, 215, 90)
        d.Parent = T
    else
        T = J:FindFirstChild("Container")
        if T then
            q = T:FindFirstChildOfClass("UIListLayout")
            d = T:FindFirstChild("MainLabel")
            u = T:FindFirstChild("MutLabel")
        end
    end
    if not d then return end
    local E = j.Name
    local a = h.StringToColor3Light(E)
    local H = g.GetFruitVariant(G)
    local r = TJ(g.GetFruitWeight(G))
    local Y = h.StringToColor3Light(H)
    local e = string.format("<font color=\'%s\'>%s</font> - <font color=\'%s\'>%s</font>", Y, H, a, E)
    local s = string.format("%skg", r)
    local N = require((game:GetService("ReplicatedStorage")).Modules.CalculatePlantValue)
    local W = y.CalculatePlantValue(G) or 0
    local X = "$" .. h.formatShecklesNumber(W)
    d.Text = string.format(
        "<stroke color=\'#000000\' thickness=\'2\'><font color=\'#000000\'>%s</font> <font color=\'#FFFFFF\'>%s</font></stroke> \226\128\162 <stroke color=\'#000000\' thickness=\'2\'><font color=\'#00F51E\'>%s</font></stroke> ",
        e, s, X)
    local l = false
    if V then
        local V = G:GetAttributes()
        local y = {}
        for G, V in pairs(V) do
            if i.AllFruitMutations[G] then
                local V = string.format("<font color=\'%s\'>%s</font>", h.StringToColor3Light(G), G)
                table.insert(y, V)
            end
        end
        if #y > 0 then
            l = true
            local G = #y
            local V = table.concat(y, " \226\128\162 ")
            local Z = string.format(
                "[%s] <stroke color=\'#000000\' thickness=\'1\'><font color=\'#FFFFFF\'>%s</font></stroke>", G, V)
            if not u then
                u = Instance.new("TextLabel")
                u.Name = "MutLabel"
                u.Size = UDim2.fromScale(1, 0)
                u.AutomaticSize = Enum.AutomaticSize.Y
                u.BackgroundTransparency = 1
                u.TextScaled = false
                u.TextSize = 11
                u.RichText = true
                u.TextWrapped = true
                u.Font = Enum.Font.GothamBold
                u.TextStrokeTransparency = .6
                u.TextStrokeColor3 = Color3.new(0, 0, 0)
                u.TextColor3 = Color3.fromRGB(255, 230, 160)
                u.Parent = T
            end
            u.Text = Z
            u.Visible = true
        else
            if u then u.Visible = false end
        end
    end
    if q then q:ApplyLayout() end
    local B = q.AbsoluteContentSize.Y
    if B < 50 then B = 50 end
    J.Size = UDim2.fromOffset(400, B + 10)
end
i.FruitMakeSmall = function()
    local G = d.fruitesp.plants_list or {}
    if next(G) == nil then return end
    local V = H.Get_Plants_Physical_Objects()
    local y = 1.5
    for V, Z in ipairs(V) do
        if not G[Z.Name] then continue end
        local j = Z:FindFirstChild("Fruits")
        if not j then
            h.CreateFruitESP(Z, true, true)
            continue
        end
        for G, V in ipairs(j:GetChildren()) do
            if V:GetAttribute("IsSmallx") then
                h.CreateFruitESP(V, true, true)
                continue
            end
            local Z = V.PrimaryPart or V:FindFirstChild("Base")
            if not Z then continue end
            local j = Z.CFrame
            V:SetAttribute("IsSmallx", true)
            local i = V:GetPivot()
            V:ScaleTo(y)
            V:PivotTo(i)
            for G, V in ipairs(V:GetDescendants()) do if V:IsA("BasePart") then V.CanCollide = false end end
        end
    end
end
task.spawn(function()
