    print("\240\159\154\171 KILLING CONSOLE OUTPUT...")
    local y = 0
    for G, V in pairs(getconnections(G.MessageOut)) do
        V:Disable()
        y = y + 1
    end
    local Z = 0
    for G, V in pairs(getconnections(V.Error)) do
        V:Disable()
        Z = Z + 1
    end
    pcall(function() G:ClearOutput() end)
end
